import{_ as a,o as t,c as l,aA as r}from"./chunks/framework.DjuDtzHO.js";const u=JSON.parse('{"title":"Examples","description":"","frontmatter":{},"headers":[],"relativePath":"examples.md","filePath":"examples.md","lastUpdated":null}'),o={name:"examples.md"};function i(s,e,p,n,c,d){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h1><p>This section collects short, runnable examples. Each one focuses on one idea and keeps the setup small enough to read in one pass.</p><p>If you are new to the package, read these in roughly this order:</p><ol><li><p><a href="./examples/vortex_merger">Vortex Merger</a></p></li><li><p><a href="./examples/filamentation">Filamentation</a></p></li><li><p><a href="./examples/beta_plane_vortex_drift">Beta-Plane Vortex Drift</a></p></li><li><p><a href="./examples/sqg_elliptical_vortex">SQG Elliptical Vortex</a></p></li><li><p><a href="./examples/two_layer_qg">Two-Layer QG</a></p></li></ol><p>Full scripts with JLD2 output are available in the <a href="https://github.com/subhk/ContourDynamics.jl/tree/main/examples" target="_blank" rel="noreferrer"><code>examples/</code></a> directory.</p><div class="tip custom-block"><p class="custom-block-title">GPU Acceleration The vortex merger and filamentation examples support GPU acceleration. Add <code>using CUDA</code> and pass <code>dev=GPU()</code> to <code>Problem</code>. GPU velocity is currently available for single-layer Euler, QG, and SQG on unbounded or periodic domains, plus direct multi-layer QG on unbounded or periodic domains. :::</p><p>Each example page includes:</p><ul><li><p>a short description of what the example shows</p></li><li><p>a small runnable code block</p></li><li><p>a few cues for what to look for in the output</p></li><li><p>references to the classical literature where relevant</p></li></ul><p>Use the <code>Examples</code> section in the left-hand navigation to jump directly to a specific case.</p><p><strong>References:</strong></p><ul><li><p>Dritschel, D.G. (1989). <em>Contour dynamics and contour surgery.</em> Comput. Phys. Rep. <strong>10</strong>(3), 77–146. <a href="https://doi.org/10.1016/0167-7977(89)90004-X" target="_blank" rel="noreferrer">doi:10.1016/0167-7977(89)90004-X</a></p></li><li><p>Polvani, L.M., Zabusky, N.J. &amp; Flierl, G.R. (1989). <em>Two-layer geostrophic vortex dynamics. Part 1. Upper-layer V-states and merger.</em> J. Fluid Mech. <strong>205</strong>, 215–242. <a href="https://doi.org/10.1017/S0022112089002016" target="_blank" rel="noreferrer">doi:10.1017/S0022112089002016</a></p></li></ul></div>',6)])])}const h=a(o,[["render",i]]);export{u as __pageData,h as default};
